import{o as l,a as i,c as r}from"./app.8935f5f1.js";const n={},o=[r("<li>互联网架构<strong>并非靠设计出来</strong>的，而是经过<strong>实战不断演练</strong>而成，因此经验尤为重要。</li><li>代码量是无法真正权衡水平的，在做需求时多去思考更合理的解决方案、写代码时尽量避免重复劳动，才是我们要追求的。</li><li>实际软件工程项目中，模块切分的太大则会产生模块化不足的现象，模块切分的太小则会陷入过度模块化陷阱。</li><li>模块化不足会让你的项目失去灵活性，并且与业务高度耦合，相同的代码不得不写多次才能实现同样的功能； <ul><li>而过度模块化则会让程序员记忆成本增加，并可能出现只有在特定情形下多个模块组合才能达成某个目的的“魔法组合方式”，不利于维护。</li></ul></li><li>随着业务的变化、系统设计也要持续演进升级。 <ul><li><strong>没有一开始就完美的架构， 好的架构设计一定是演化来的，不是一开始就设计出来的。</strong></li></ul></li>",5)];n.render=function(r,n){return l(),i("ul",null,o)};export{n as default};
